var e=[{id:`L2_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`이봐! 아가씨들! 그쪽 상황은 어때?`,JPN:`おい、嬢ちゃんたち！　そっちの状況はどうだ？`,ENG:`Hey! Ladies! How's it going over there?`,TWN:`喂！小姐們！你們那裡情況怎麼樣啦？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`치즈케이크에 커피 한 잔 할 여유는 있나?!`,JPN:`チーズケーキとコーヒー1杯くらい楽しむ余裕はあるか！？`,ENG:`Enjoying a little tea time, are you?`,TWN:`有空喝杯咖啡搭配起司蛋糕嗎？！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`가족이랑 사촌들 안부는 다 물었고?`,JPN:`家族や親戚の安否も確認できたか？`,ENG:`Done with your chitchat?`,TWN:`已經跟家人和表兄弟姊妹們都問好了嗎？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`여긴...... 젠장, 피해!`,JPN:`ここは……ちくしょう、逃げろ！`,ENG:`As for the situation here... Damn it! Watch out!`,TWN:`這裡……該死，出現傷者了！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`JERRY_MASON_NULL_NULL`,text:{KOREA:`으아아! 내 등에 불 붙었어!`,JPN:`うわあ！　俺の背中に火が点いたよ！`,ENG:`Aaah! My back is on fire!`,TWN:`啊啊啊！我的背後著火啦！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JERRY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`TOMY_MASON_NULL_NULL`,text:{KOREA:`비켜! 내가 꺼 줄게!`,JPN:`どけ！　俺が消してやる！`,ENG:`Get down! I’ll snuff it out for you!`,TWN:`閃開！我來幫他滅火！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`TOMY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MICKEY_MASON_NULL_NULL`,text:{KOREA:`야! 그렇다고 몸으로 덮치면 어떡해!`,JPN:`おい！　だからって、いきなり覆い被さってどうする！`,ENG:`Hey! That doesn’t mean you should tackle him!`,TWN:`喂！就算這樣，你也用不著壓在他身上啊！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`MICKEY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MICKEY_MASON_NULL_NULL`,text:{KOREA:`제리가 숨을 못 쉬는 것 같은데?!`,JPN:`ジェリーが息してないみたいだぞ！？`,ENG:`I don’t think Jerry's breathing anymore!`,TWN:`傑瑞好像沒有呼吸了耶？！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`MICKEY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ZHANG_MASON_NULL_NULL`,text:{KOREA:`사장님! 해외출장이라고 해서 따라왔는데 이게 뭐에요!`,JPN:`社長！　海外出張だと言うからついて来たのに、これはどういうことですか！`,ENG:`Boss! This wasn’t what I had in mind when you said “international business trip!”`,TWN:`老闆！你說要海外出差我才跟來的，但現在這算什麼啊！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`ZHANG_MASON_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ZHANG_MASON_NULL_NULL`,text:{KOREA:`나 디트로이트로 돌아갈래!`,JPN:`私、デトロイトに帰る！`,ENG:`I’m gonna go back to Detroit!`,TWN:`我要回底特律！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`ZHANG_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`시끄러워! 혼자 해외여행 가는 꼴은 못 본다고 억지로 따라온 건 너잖아!`,JPN:`やかましい！　1人で海外旅行はずるいって、お前が無理やりついてきたんだろ！`,ENG:`Oh, shut it. You're the one who tagged along because you were jealous of me “traveling” abroad!`,TWN:`吵死了！明明是妳見不得我一個人要去海外出差，所以才硬要跟來的不是嗎！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`고개나 잘 숙이고 있어!`,JPN:`いいからちゃんと頭を下げていろよ！`,ENG:`Just keep your head down!`,TWN:`給我好好低著頭！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`......여긴, 보다시피 좀 바쁜데 말이지!`,JPN:`……こっちは、見ての通りちょっと忙しくてな！`,ENG:`As you can see... We're a little busy here!`,TWN:`……我這裡如你們所見，忙得不得了。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`수다 떠는 거 다 끝났으면 좀 도와주면 안 될까?`,JPN:`おしゃべりが終わったなら、ちょっとばかし手伝ってくれないか？`,ENG:`If you're done chatting, could you give us a hand?`,TWN:`如果你們已經聊完了，能不能來幫我一點忙啊？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`불평하고 싶진 않지만, 젠장!`,JPN:`文句は言いたくないが……ちくしょう！`,ENG:`I don’t want to whine or anything... but damn it!`,TWN:`雖然我不是很想抱怨，該死！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`이쪽엔 카운터 전력이 한 명도 없다고!`,JPN:`こっちにはカウンターが1人もいないんだよ！`,ENG:`We don’t have a single Counter here!`,TWN:`但我這裡連一個可以戰鬥的制裁者都沒有！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};